import { describe, expect, test } from 'vitest';
import Defuddle from './src/index.full';
import { parseLinkedomHTML } from './src/utils/linkedom-compat';

function parse(content: string, markdown = true) {
  const html = `<!doctype html>
<html>
<head><title>Empty table article</title></head>
<body><article>${content}</article></body>
</html>`;
  const doc = parseLinkedomHTML(html, 'https://example.com/empty-table');
  return new Defuddle(doc, { markdown, url: 'https://example.com/empty-table' }).parse();
}

describe('empty table reproduction', () => {
  test('drops visual tables whose cells have no text while preserving data tables', () => {
    const result = parse(`
      <table class="pr_quality" title="1 validated page, 10 only proofread pages">
        <tr>
          <td class="quality4" style="width: 8.33%"></td>
          <td class="quality3" style="width: 83.33%"></td>
          <td class="quality2" style="width: 0%"></td>
          <td class="quality1" style="width: 0%"></td>
          <td class="quality0" style="width: 8.33%"></td>
          <td class="qualitye" style="width: 0%"></td>
        </tr>
      </table>
      <h1>Empty table article</h1>
      <p>Actual article text with enough words to be selected as main readable content.</p>
      <table>
        <tr><th>Name</th><th>Value</th></tr>
        <tr><td>Alpha</td><td>42</td></tr>
      </table>
    `);

    expect(result.content).toContain('Actual article text');
    expect(result.content).not.toContain('|  |  |');
    expect(result.content).toContain('| Name | Value |');
    expect(result.content).toContain('| Alpha | 42 |');
  });

  test('drops whitespace-only and nonbreaking-space-only tables from HTML output', () => {
    const result = parse(`
      <p>Actual article text with enough words to be selected as main readable content.</p>
      <table class="spacer"><tr><td>   </td><td>&nbsp;</td></tr></table>
      <p>Second paragraph remains available for extraction after the spacer table.</p>
    `, false);

    expect(result.content).toContain('Actual article text');
    expect(result.content).toContain('Second paragraph remains');
    expect(result.content).not.toContain('<table');
    expect(result.content).not.toContain('spacer');
  });
});
EOF
npx vitest run .tmp-empty-table-repro.test.ts --reporter=verbose

